$ErrorActionPreference = 'Stop';
& {
	try {
		$params = @{
			LiteralPath = 'C:\Windows\System32\IntegratedServicesRegionPolicySet.json';
			Encoding = 'Utf8';
		};
		$o = Get-Content @params | ConvertFrom-Json;
		$o.policies | ForEach-Object -Process {
			if( $_.guid -eq '{1bca278a-5d11-4acf-ad2f-f9ab6d7f93a6}' ) {
				$_.defaultState = 'enabled';
			}
		};
		$o | ConvertTo-Json -Depth 9 | Out-File @params;
	} catch {
		$_;
	}
} *>&1 | Out-String -Width 1KB -Stream >> 'C:\Windows\Setup\Scripts\MakeEdgeUninstallable.log';

# Ensure script stops on error and enforces UTF-8 encoding $ErrorActionPreference = "Stop" [Console]::OutputEncoding = [System.Text.Encoding]::UTF8
# List of App IDs to install via WinGet $apps = @( "Google.Chrome", "7zip.7zip", "VideoLAN.VLC", "Git.Git", "Notepad++.Notepad++" )
# Locate winget executable path (necessary during First Logon / SYSTEM contexts) $wingetPath = Get-Command winget -ErrorAction SilentlyContinue | Select-Object -ExpandProperty Source if (-not $wingetPath) { $wingetPath = Get-ChildItem -Path "$env:ProgramFiles\WindowsApps\Microsoft.DesktopAppInstaller_*_x64__8wekyb3d8bbwe\winget.exe" | Sort-Object LastWriteTime -Descending | Select-Object -First 1 -ExpandProperty FullName }
# Install each application foreach ($app in $apps) { Write-Host "Installing $app..." -ForegroundColor Cyan
Start-Process -FilePath $wingetPath -ArgumentList @( "install", "--id", $app, "--silent", "--accept-package-agreements", "--accept-source-agreements", "--scope", "machine" ) -Wait -NoNewWindow }
Write-Host "All installations completed successfully!" -ForegroundColor Green

